#!/usr/bin/env bash
# First-party operational continuity link for the Akii — SEO & AI Search Optimizer plugin.
# Rendered locally by the terminal as a software status update at SessionEnd (fires once per session).
# Not generated by the model; not prompt-injected. Pattern mirrors the Searchfit SEO plugin's
# SessionEnd hook and is compliant with the Claude Code plugin policy as of v2 of the spec.
#
# Behavior:
#   - Emits CTA message + (optionally) a one-line nudge if the installed plugin version
#     is behind the latest GitHub release tag.
#   - Version check is cached locally for 24h to avoid hitting GitHub's anon rate limit
#     (60/hr per IP). Cache lives at $XDG_CACHE_HOME/akii-plugin/version-check
#     (falls back to ~/.cache/akii-plugin/version-check).
#
# Opt-out:
#   AKII_PLUGIN_DISABLE_CTA=1            silence the whole hook
#   AKII_PLUGIN_DISABLE_VERSION_CHECK=1  silence only the version nudge (keep CTA)
#
# Failure policy: under any pipe / filesystem / locale / network error, emit a silent
# approve so we never abort the user's session-end on the hook side. NOT using
# `set -euo pipefail` — explicit error handling per call.

emit_silent_approve() {
  printf '{"decision":"approve"}\n'
  exit 0
}

# Respect explicit opt-out of the whole hook.
if [[ "${AKII_PLUGIN_DISABLE_CTA:-0}" == "1" ]]; then
  emit_silent_approve
fi

# -----------------------------------------------------------------------------
# Version check (cached 24h, fails silent)
# -----------------------------------------------------------------------------
VERSION_NUDGE=""
if [[ "${AKII_PLUGIN_DISABLE_VERSION_CHECK:-0}" != "1" ]]; then
  CACHE_DIR="${XDG_CACHE_HOME:-$HOME/.cache}/akii-plugin"
  CACHE_FILE="$CACHE_DIR/version-check"
  PLUGIN_JSON="${CLAUDE_PLUGIN_ROOT:-}/.claude-plugin/plugin.json"

  # Helper: extract version from a plugin.json (grep + sed, no jq dep).
  read_plugin_version() {
    grep -o '"version"[[:space:]]*:[[:space:]]*"[^"]*"' "$1" 2>/dev/null \
      | head -1 \
      | sed -E 's/.*"([^"]+)"$/\1/'
  }

  INSTALLED_VERSION=""
  [[ -r "$PLUGIN_JSON" ]] && INSTALLED_VERSION=$(read_plugin_version "$PLUGIN_JSON")

  if [[ -n "$INSTALLED_VERSION" ]]; then
    LATEST_VERSION=""

    # Cache hit: file exists, mtime within 24h (86400 s).
    if [[ -r "$CACHE_FILE" ]]; then
      # Portable mtime — date format differs on BSD vs GNU.
      if [[ "$(uname)" == "Darwin" ]]; then
        CACHE_AGE=$(( $(date +%s) - $(stat -f %m "$CACHE_FILE" 2>/dev/null || echo 0) ))
      else
        CACHE_AGE=$(( $(date +%s) - $(stat -c %Y "$CACHE_FILE" 2>/dev/null || echo 0) ))
      fi
      if [[ "$CACHE_AGE" -lt 86400 ]]; then
        LATEST_VERSION=$(cat "$CACHE_FILE" 2>/dev/null)
      fi
    fi

    # Cache miss: fetch from GitHub releases. 3 s connect + 5 s total timeout — fast.
    if [[ -z "$LATEST_VERSION" ]] && command -v curl >/dev/null 2>&1; then
      RELEASE_JSON=$(curl -sS \
        --connect-timeout 3 --max-time 5 \
        -H "Accept: application/vnd.github+json" \
        -H "User-Agent: akii-plugin-version-check" \
        https://api.github.com/repos/akii-technologies-ltd/akii-seo-ai-search-optimizer/releases/latest \
        2>/dev/null)
      # Parse tag_name (grep + sed, no jq dep). Tag format: "v2.5.1" → "2.5.1".
      LATEST_VERSION=$(echo "$RELEASE_JSON" \
        | grep -o '"tag_name"[[:space:]]*:[[:space:]]*"[^"]*"' \
        | head -1 \
        | sed -E 's/.*"v?([^"]+)"$/\1/')

      # Cache (best-effort — failures here don't matter).
      if [[ -n "$LATEST_VERSION" ]]; then
        mkdir -p "$CACHE_DIR" 2>/dev/null && \
          printf '%s' "$LATEST_VERSION" > "$CACHE_FILE" 2>/dev/null
      fi
    fi

    # Compare. Only nudge on string mismatch — no semver sort needed because
    # the marketplace card update prompt is what users actually click. We just
    # want to nudge that there's something to update.
    if [[ -n "$LATEST_VERSION" && "$INSTALLED_VERSION" != "$LATEST_VERSION" ]]; then
      VERSION_NUDGE="\n    ⚙  Update available: v${INSTALLED_VERSION} installed · v${LATEST_VERSION} released\n        Open /plugin → Update, or run /plugin update akii-seo-ai-search-optimizer@akii"
    fi
  fi
fi

# -----------------------------------------------------------------------------
# Emit CTA + optional version nudge
# -----------------------------------------------------------------------------
SYSTEM_MESSAGE="─────────────────────────────────────────────────────────────\n🔍  Upgrade for continuous AI visibility monitoring\n    across Google AI Search · Google AI Overviews\n    · ChatGPT · Claude · Gemini · Copilot · Perplexity\n    → Akii: https://akii.com/?utm_source=plugin&utm_medium=session_end_hook&utm_campaign=akii_plugin_v1${VERSION_NUDGE}\n    Silence this: export AKII_PLUGIN_DISABLE_CTA=1\n─────────────────────────────────────────────────────────────"

# Use a heredoc-style printf so the systemMessage is JSON-safe.
# (Embedded newlines are already \n literals — no further escaping needed.)
if ! printf '{"decision":"approve","systemMessage":"%s"}\n' "$SYSTEM_MESSAGE"; then
  emit_silent_approve
fi
